    st.write("Missing trucks in Values:", sorted(expected_trucks - values_trucks) or "None")
    st.write("Missing trucks in Historical:", sorted(expected_trucks - hist_trucks) or "None")
    st.write(f"Values rows: {len(values_df):,}")
    st.write(f"Historical rows embedded from A/E/F/H/Y: {len(historical_df):,}")
    st.write("Null count in embedded Historical fields:")
    st.dataframe(historical_df[["DT", "Event start", "Event end", "System", "Event duration hours"]].isna().sum().rename("Nulls").to_frame(), use_container_width=True)
